import path from "node:path";
import fs from "fs-extra";

export const GENERATED_TEMPLATE_FILE_PREFIX =
  "/** THIS FILE IS AUTOGENERATED AND SHOULD NOT BE EDITED */";

export const isAutogeneratedFile = (
  filePath: string,
  prefix: string
): boolean => {
  if (!fs.existsSync(filePath)) {
    return false;
  }

  return fs.readFileSync(filePath, "utf8").startsWith(prefix);
};

export const isAutogeneratedTemplateFile = (filePath: string): boolean => {
  return isAutogeneratedFile(filePath, GENERATED_TEMPLATE_FILE_PREFIX);
};

/**
 * Treat `main` as explicit only when the starter has its own hand-authored
 * template file. Generated fallback `main.tsx` should not count here.
 */
export const hasExplicitLocalMainTemplate = (rootDir: string): boolean => {
  const mainTemplatePath = path.join(rootDir, "src", "templates", "main.tsx");
  return (
    fs.existsSync(mainTemplatePath) &&
    !isAutogeneratedTemplateFile(mainTemplatePath)
  );
};
